      </div>

      <h3>Medical History</h3>
      <p><strong>Past Diagnoses:</strong> {history.past_diagnoses}</p>
      <p><strong>Surgeries:</strong> {history.surgeries}</p>
      <p><strong>Hospital Admissions:</strong> {history.hospital_admissions}</p>
