        </div>

        <form onSubmit={handleManualSubmit} className="manual-input-form" style={{ marginTop: '10px', display: 'flex', gap: '5px' }}>
          <input 
            type="text" 
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
